// v5: Query rotation with builder-language searches
const tokenItem = $input.first();
const token = tokenItem?.json?.fields?.Value || tokenItem?.json?.Value || '';

// Query definitions with priority tiers
const queries = [
  // HIGH PRIORITY (run daily) - Title-based
  { id: 'q1', query: 'Head of Customer Support B2B SaaS', priority: 'high' },
  { id: 'q2', query: 'Director Customer Support SaaS startup', priority: 'high' },
  { id: 'q3', query: 'Director Customer Support healthcare SaaS', priority: 'high' },
  { id: 'q4', query: 'Head of Customer Support developer tools', priority: 'high' },
  // HIGH PRIORITY (run daily) - Builder language
  { id: 'q9', query: '"founding" customer success SaaS', priority: 'high' },
  { id: 'q10', query: '"first hire" customer support SaaS', priority: 'high' },
  { id: 'q11', query: '"build" customer support team startup', priority: 'high' },
  // MEDIUM PRIORITY (every 2 days)
  { id: 'q5', query: 'Head of Customer Experience B2B SaaS', priority: 'medium' },
  { id: 'q6', query: 'VP Customer Support SaaS', priority: 'medium' },
  { id: 'q7', query: 'Head of Support SaaS startup', priority: 'medium' },
  { id: 'q12', query: '"ground up" customer success startup', priority: 'medium' },
  { id: 'q13', query: '"0 to 1" customer success', priority: 'medium' },
  { id: 'q14', query: '"first customer success" hire startup', priority: 'medium' },
  // LOW PRIORITY (every 3 days)
  { id: 'q8', query: 'founding support leader SaaS', priority: 'low' },
  { id: 'q15', query: '"build customer support from scratch"', priority: 'low' }
];

// Determine which queries to run based on day
const dayOfYear = Math.floor((Date.now() - new Date(new Date().getFullYear(), 0, 0)) / 86400000);
const runHigh = true; // Always run high priority
const runMedium = dayOfYear % 2 === 0; // Every 2 days
const runLow = dayOfYear % 3 === 0; // Every 3 days

const todaysQueries = queries.filter(q => {
  if (q.priority === 'high') return runHigh;
  if (q.priority === 'medium') return runMedium;
  if (q.priority === 'low') return runLow;
  return false;
});

// Return all queries for this run
return todaysQueries.map(q => ({
  json: {
    browserlessToken: token,
    searchUrl: `https://www.indeed.com/jobs?q=${encodeURIComponent(q.query)}&l=remote&fromage=7&remotejob=032b3046-06a3-4876-8dfd-474eb5e7ed11`,
    queryId: q.id,
    queryText: q.query,
    priority: q.priority,
    isBuilderQuery: q.id >= 'q9'
  }
}));

// v5: Parse Indeed response with query tracking
const item = $input.first().json;
const response = item.data || item;
const queryId = item.queryId || $('Build Search Query').first()?.json?.queryId || 'unknown';
const queryText = item.queryText || $('Build Search Query').first()?.json?.queryText || '';
const isBuilderQuery = item.isBuilderQuery || $('Build Search Query').first()?.json?.isBuilderQuery || false;

if (response.error) {
  return [{ json: { _error: response.error, queryId } }];
}

const jobs = response.jobs || [];

if (jobs.length === 0) {
  return [{ json: { _empty: true, _message: 'No jobs found', queryId } }];
}

const supportKeywords = ['support', 'success', 'customer', 'client', 'cx', 'experience'];
const leadershipKeywords = ['head', 'director', 'vp', 'vice president', 'chief', 'lead', 'manager', 'supervisor', 'founding', 'first'];

const filtered = jobs.filter(job => {
  const title = (job.title || '').toLowerCase();
  return supportKeywords.some(kw => title.includes(kw)) && leadershipKeywords.some(kw => title.includes(kw));
});

if (filtered.length === 0) {
  return [{ json: { _empty: true, _rawCount: jobs.length, queryId } }];
}

return filtered.map(job => ({
  json: {
    'Job Title': job.title,
    'Company': job.company,
    'Location': job.location,
    'Source': 'Indeed',
    'Job URL': job.url,
    'Job ID': job.jobId,
    'Salary Info': job.salary,
    'Date Found': new Date().toISOString().split('T')[0],
    'Review Status': 'New',
    '_queryId': queryId,
    '_queryText': queryText,
    '_isBuilderQuery': isBuilderQuery
  }
}));

// Dedup new jobs against existing
const normalize = str => (str || '').toLowerCase().replace(/[^a-z0-9]/g, '');

const allItems = $input.all();
const newJobs = allItems.filter(i => i.json['Source'] === 'Indeed' && !i.json.fields && !i.json._empty && !i.json._error);
const existing = allItems.filter(i => i.json.fields);

const existingKeys = new Set();
for (const item of existing) {
  const f = item.json.fields;
  const key = normalize(f['Job Title']) + '|' + normalize(f['Company']);
  if (key.length > 1) existingKeys.add(key);
  if (f['Job ID']) existingKeys.add(f['Job ID']);
}

const results = [];
const seen = new Set();

for (const job of newJobs) {
  const key = normalize(job.json['Job Title']) + '|' + normalize(job.json['Company']);
  const jobId = job.json['Job ID'];

  if (existingKeys.has(key) || existingKeys.has(jobId) || seen.has(key)) continue;
  seen.add(key);
  results.push(job);
}

return results.length ? results : [{ json: { _empty: true } }];
